import io
import csv
import re
import boto3

try:
    from dotenv import load_dotenv
    load_dotenv('.env')
except Exception:
    pass

source = 'datagov/vehicle-registration-summary/files/rows.txt'
bucket = 'lakeqa-yc4103-datalake'
node_4_answer = '2019, 2020, 2021'
node_5_answer = 'Adams; Garfield; Grays Harbor; Island; King'
target_years = {part.strip() for part in re.findall(r'\d{4}', node_4_answer)}
target_counties = [part.strip() for part in node_5_answer.split(';') if part.strip()]
totals = {county: 0 for county in target_counties}
body = io.TextIOWrapper(boto3.client('s3').get_object(Bucket=bucket, Key=source)['Body'], encoding='utf-8', errors='replace')
reader = csv.DictReader(body)
for row in reader:
    county = str(row.get('County', '')).strip()
    if county not in totals:
        continue
    if str(row.get('State', '')).strip() != 'WA':
        continue
    if str(row.get('Fiscal Year', '')).strip() not in target_years:
        continue
    if str(row.get('Transaction Type', '')).strip() != 'Registration Renewal':
        continue
    if str(row.get('Primary Use', '')).strip() != 'Passenger Vehicle':
        continue
    if str(row.get('Vehicle Type', '')).strip() != 'PASSENGER CAR':
        continue
    totals[county] += int(str(row.get('Transaction Count', '0')).strip() or '0')
ascending = sorted(totals.items(), key=lambda item: (item[1], item[0]))
descending = sorted(totals.items(), key=lambda item: (-item[1], item[0]))
answer = f"{ascending[1][0]}; {descending[1][0]}"
